-- Step 1: Delete orphaned damage marks (depends on contracts)
DELETE FROM damageMarks WHERE contractId NOT IN (SELECT id FROM rentalContracts);
DELETE FROM damageMarks WHERE userId NOT IN (SELECT id FROM users);

-- Step 2: Delete orphaned invoices (depends on contracts)
DELETE FROM invoices WHERE contractId NOT IN (SELECT id FROM rentalContracts);
DELETE FROM invoices WHERE userId NOT IN (SELECT id FROM users);

-- Step 3: Delete orphaned maintenance records (depends on vehicles)
DELETE FROM maintenanceRecords WHERE vehicleId NOT IN (SELECT id FROM vehicles);
DELETE FROM maintenanceRecords WHERE userId NOT IN (SELECT id FROM users);

-- Step 4: Delete orphaned rental contracts (depends on users and vehicles)
DELETE FROM rentalContracts WHERE userId NOT IN (SELECT id FROM users);
DELETE FROM rentalContracts WHERE vehicleId NOT IN (SELECT id FROM vehicles);

-- Step 5: Delete orphaned clients (depends on users)
DELETE FROM clients WHERE userId NOT IN (SELECT id FROM users);

-- Verify cleanup
SELECT 'After cleanup:' as status;
SELECT 'clients' as table_name, COUNT(*) as total_records FROM clients
UNION ALL
SELECT 'invoices', COUNT(*) FROM invoices
UNION ALL
SELECT 'rentalContracts', COUNT(*) FROM rentalContracts
UNION ALL
SELECT 'maintenanceRecords', COUNT(*) FROM maintenanceRecords
UNION ALL
SELECT 'damageMarks', COUNT(*) FROM damageMarks;

